  // PiP mode - horizontal layout with image on left, similar to post-card horizontal
  if (displayMode === "pip") {
    return (
      <div className="flex flex-col sm:flex-row gap-4 rounded-lg border bg-card p-3">
        {showCover && post?.coverImage && (
